// 2. Extracted refreshTableData() safely into its own clean method block
    private void refreshTableData() {
        String[] columnHeaders = {"Book ID", "Title", "Author", "Status"};
        
        com.library.db.LibraryDAO dao = new com.library.db.LibraryDAO();
        java.util.Vector<java.util.Vector<Object>> dataRows = dao.getAllBooksForUI();
        
        javax.swing.table.DefaultTableModel model = new javax.swing.table.DefaultTableModel(dataRows, new java.util.Vector<>(java.util.Arrays.asList(columnHeaders))) {
            @Override
            public boolean isCellEditable(int row, int column) {
                return false; // Prevents direct UI editing of cells
            }
        };
        
        tableBooks.setModel(model);
    }
    private void refreshTransactionTable() {
    String[] columnHeaders = {"Tx ID", "Book Title", "Member Name", "Issue Date", "Return Status"};
    
    com.library.db.LibraryDAO dao = new com.library.db.LibraryDAO();
    java.util.Vector<java.util.Vector<Object>> dataRows = dao.getTransactionHistoryForUI();
    
    javax.swing.table.DefaultTableModel model = new javax.swing.table.DefaultTableModel(dataRows, new java.util.Vector<>(java.util.Arrays.asList(columnHeaders))) {
        @Override
        public boolean isCellEditable(int row, int column) {
            return false;
        }
    };
    
    tableTransactions.setModel(model);
}
    private void btnSaveActionPerformed(java.awt.event.ActionEvent evt) {//GEN-FIRST:event_btnSaveActionPerformed
                                       
    // 1. Gather text entries from our text field boxes
    String title = txtTitle.getText().trim();
    String author = txtAuthor.getText().trim();

    // 2. Simple form verification rule check
    if (title.isEmpty() || author.isEmpty()) {
        javax.swing.JOptionPane.showMessageDialog(this, 
                "Validation Error: Please fill up all book form inputs.", 
                "Input Warning", 
                javax.swing.JOptionPane.WARNING_MESSAGE);
        return;
    }

    // 3. Fire database instance save tracking reference
    com.library.db.LibraryDAO dao = new com.library.db.LibraryDAO();
    boolean success = dao.addBook(title, author);

    // 4. Update interface status matching result mapping state
    if (success) {
        javax.swing.JOptionPane.showMessageDialog(this, 
                "Success: Book has been saved cleanly to MySQL catalog!", 
                "Transaction Complete", 
                javax.swing.JOptionPane.INFORMATION_MESSAGE);
        
        // Clear text entry boxes so they are ready for the next entry
        txtTitle.setText("");
        txtAuthor.setText("");
    } else {
        javax.swing.JOptionPane.showMessageDialog(this, 
                "Database Error: Failed to add book record. Check your local server connection logs.", 
                "System Error", 
                javax.swing.JOptionPane.ERROR_MESSAGE);
    }

    }//GEN-LAST:event_btnSaveActionPerformed

    private void btnRefreshActionPerformed(java.awt.event.ActionEvent evt) {//GEN-FIRST:event_btnRefreshActionPerformed
        // TODO add your handling code here:
        refreshTableData();
    }//GEN-LAST:event_btnRefreshActionPerformed

    
    private void btnRegisterMemberActionPerformed(java.awt.event.ActionEvent evt) {//GEN-FIRST:event_btnRegisterMemberActionPerformed
        // TODO add your handling code here:
        String name = txtMemberName.getText().trim();
    String email = txtMemberEmail.getText().trim();

    // 1. Validation Check
    if (name.isEmpty() || email.isEmpty()) {
        javax.swing.JOptionPane.showMessageDialog(this, 
                "Validation Error: Please fill up all member registration inputs.", 
                "Input Warning", 
                javax.swing.JOptionPane.WARNING_MESSAGE);
        return;
    }

    // 2. Database Insert Operation
    // Inside MainApp.java -> look for btnRegisterMemberActionPerformed
com.library.db.LibraryDAO dao = new com.library.db.LibraryDAO();
boolean success = dao.registerMember(name, email); // Make sure it says registerMember

    // 3. UI Update Status Notification
    if (success) {
        javax.swing.JOptionPane.showMessageDialog(this, 
                "Success: New member has been registered cleanly!", 
                "Registration Complete", 
                javax.swing.JOptionPane.INFORMATION_MESSAGE);
        
        // Clear input boxes
        txtMemberName.setText("");
        txtMemberEmail.setText("");
    } else {
        javax.swing.JOptionPane.showMessageDialog(this, 
                "Database Error: Failed to register member. Ensure email is unique and check logs.", 
                "System Error", 
                javax.swing.JOptionPane.ERROR_MESSAGE);
    }

    }//GEN-LAST:event_btnRegisterMemberActionPerformed

    private void btnIssueBookActionPerformed(java.awt.event.ActionEvent evt) {//GEN-FIRST:event_btnIssueBookActionPerformed
        // TODO add your handling code here:
        String bookIdStr = txtIssueBookId.getText().trim();
    String memberIdStr = txtIssueMemberId.getText().trim();

    // 1. Validation Check
    if (bookIdStr.isEmpty() || memberIdStr.isEmpty()) {
        javax.swing.JOptionPane.showMessageDialog(this, 
                "Validation Error: Please provide both Book ID and Member ID.", 
                "Input Warning", 
                javax.swing.JOptionPane.WARNING_MESSAGE);
        return;
    }

    try {
        // 2. Parse inputs to integers
        int bookId = Integer.parseInt(bookIdStr);
        int memberId = Integer.parseInt(memberIdStr);

        // 3. Process via DAO
        com.library.db.LibraryDAO dao = new com.library.db.LibraryDAO();
        boolean success = dao.issueBook(bookId, memberId);

        if (success) {
            javax.swing.JOptionPane.showMessageDialog(this, 
                    "Success: Book has been successfully issued!", 
                    "Transaction Confirmed", 
                    javax.swing.JOptionPane.INFORMATION_MESSAGE);
            
            txtIssueBookId.setText("");
            txtIssueMemberId.setText("");
            refreshTableData(); // Instant sync to show the updated 'Borrowed' status in your catalog!
            refreshTransactionTable(); // Instantly displays the new borrow row in your log!
        } else {
            javax.swing.JOptionPane.showMessageDialog(this, 
                    "Database Error: Failed to issue book. Verify IDs exist and try again.", 
                    "System Error", 
                    javax.swing.JOptionPane.ERROR_MESSAGE);
        }
    } catch (NumberFormatException e) {
        javax.swing.JOptionPane.showMessageDialog(this, 
                "Input Error: IDs must be valid numeric digits.", 
                "Format Warning", 
                javax.swing.JOptionPane.ERROR_MESSAGE);
    }
    
    }//GEN-LAST:event_btnIssueBookActionPerformed

