    private void txtSearchKeyReleased(java.awt.event.KeyEvent evt) {//GEN-FIRST:event_txtSearchKeyReleased
        // TODO add your handling code here:
                                           
    String keyword = txtSearch.getText().trim();
    
    // If the search bar is empty, load the standard full catalog
    if (keyword.isEmpty()) {
        refreshTableData();
        return;
    }
    
    // Otherwise, bind the filtered data matching the keyword to the JTable model
    String[] columnHeaders = {"Book ID", "Title", "Author", "Status"};
    com.library.db.LibraryDAO dao = new com.library.db.LibraryDAO();
    java.util.Vector<java.util.Vector<Object>> dataRows = dao.searchBooksForUI(keyword);
    
    javax.swing.table.DefaultTableModel model = new javax.swing.table.DefaultTableModel(dataRows, new java.util.Vector<>(java.util.Arrays.asList(columnHeaders))) {
        @Override
        public boolean isCellEditable(int row, int column) {
            return false; 
        }
    };
    
    tableBooks.setModel(model);

    }//GEN-LAST:event_txtSearchKeyReleased

    private void btnReturnBookActionPerformed(java.awt.event.ActionEvent evt) {//GEN-FIRST:event_btnReturnBookActionPerformed
        // TODO add your handling code here:
        String bookId = txtReturnBookId.getText().trim();
    if(bookId.isEmpty()) return;
    
    // Quick SQL update to make the book available again
    String sql = "UPDATE books SET status = 'Available' WHERE book_id = ?";
    try (java.sql.Connection conn = com.library.db.DatabaseConnection.getConnection();
         java.sql.PreparedStatement ps = conn.prepareStatement(sql)) {
        ps.setInt(1, Integer.parseInt(bookId));
        ps.executeUpdate();
        javax.swing.JOptionPane.showMessageDialog(this, "Book Returned Successfully!");
        refreshTableData(); // Refresh your main catalog tab grid
        txtReturnBookId.setText("");
    } catch (Exception e) { System.err.println(e.getMessage()); }

    }//GEN-LAST:event_btnReturnBookActionPerformed
   
